   103→  // Update category decisions
   104→  updateCategoryDecisions(candidateScores, selectedLabels, thresholds);
   105→
   106→  // Determine AI classification need
   107→  const needsAiClassification = determineAiClassificationNeed(selectedLabels, thresholds);
   108→
   109→  const duration = Date.now() - startTime;
