   123→  result.selectedLabels = selectedLabels;
   124→  result.candidateScores = candidateScores;
   125→  result.needsAiClassification = needsAiClassification;
   126→  result.selectionSummary = {
   127→    totalLabels: selectedLabels.length,
   128→    primaryCategory: selectedLabels.find((l) => l.isPrimary)?.category || null,
   129→    confidenceRange:
