   196→/**
   197→ * Validate configuration parameters
   198→ */
   199→function validateConfiguration(config: MultiLabelConfig, thresholds: ConfidenceThresholds): void {
   200→  if (config.maxLabels < 0) {
   201→    throw new Error('Invalid configuration: maxLabels cannot be negative');
   202→  }
   203→
   204→  if (config.minSecondaryConfidence < 0) {
   205→    throw new Error('Invalid configuration: minSecondaryConfidence cannot be negative');
   206→  }
   207→
   208→  if (thresholds.highConfidence <= thresholds.mediumConfidence) {
   209→    throw new Error('Invalid threshold configuration: highConfidence must be greater than mediumConfidence');
   210→  }
   211→
   212→  if (thresholds.mediumConfidence <= thresholds.lowConfidence) {
   213→    throw new Error('Invalid threshold configuration: mediumConfidence must be greater than lowConfidence');
   214→  }
   215→
   216→  if (thresholds.secondaryLabelMinGap < 0) {
   217→    throw new Error('Invalid threshold configuration: secondaryLabelMinGap cannot be negative');
   218→  }
   219→}
   220→
   221→/**
   222→ * Rank categories by score in descending order, filtering out zero/negative scores
   223→ */
   224→function rankCategoriesByScore(candidateScores: Record<string, CategoryScore>): Array<{
   225→  category: string;
   226→  score: number;
   227→  confidence: number;
   228→  rationale: string;
   229→  selectedSubtypeId?: string | null;
   230→}> {
   231→  return Object.entries(candidateScores)
   232→    .map(([category, scoreData]) => ({
   233→      category,
   234→      score: scoreData.score || 0,
   235→      confidence: scoreData.confidence || 0,
   236→      rationale: scoreData.rationale || '',
   237→      selectedSubtypeId: scoreData.selectedSubtypeId,
   238→    }))
   239→    .filter((item) => item.score > 0)
   240→    .sort((a, b) => {
   241→      // Primary sort by score (descending)
   242→      if (b.score !== a.score) {
   243→        return b.score - a.score;
   244→      }
   245→      // Secondary sort by category name for stable ordering
   246→      return a.category.localeCompare(b.category);
   247→    });
   248→}
   249→
   250→/**
   251→ * Select secondary labels within gap threshold and above minimum confidence
   252→ */
   253→function selectSecondaryLabels(
   254→  rankedCategories: Array<{
   255→    category: string;
   256→    score: number;
   257→    confidence: number;
   258→    rationale: string;
   259→    selectedSubtypeId?: string | null;
   260→  }>,
   261→  selectedLabels: SelectedLabel[],
   262→  primaryCandidate: {
   263→    category: string;
   264→    score: number;
   265→    confidence: number;
   266→    rationale: string;
   267→    selectedSubtypeId?: string | null;
   268→  },
   269→  config: MultiLabelConfig,
   270→  thresholds: ConfidenceThresholds
   271→): void {
   272→  if (config.maxLabels <= 1 || rankedCategories.length <= 1) {
   273→    return;
   274→  }
   275→
   276→  const primaryScore = primaryCandidate.score;
   277→
   278→  for (let i = 1; i < rankedCategories.length && selectedLabels.length < config.maxLabels; i++) {
   279→    const candidate = rankedCategories[i];
   280→    const scoreDifference = primaryScore - candidate.score;
   281→
   282→    // Check if candidate meets secondary label criteria
   283→    if (candidate.score >= config.minSecondaryConfidence && scoreDifference <= thresholds.secondaryLabelMinGap) {
   284→      // Check if combination is allowed
   285→      if (isCombinationAllowed(primaryCandidate.category, candidate.category, config)) {
   286→        const secondaryLabel: SelectedLabel = {
   287→          category: candidate.category,
   288→          subtype: candidate.selectedSubtypeId || null,
   289→          confidence: candidate.confidence,
   290→          score: candidate.score,
   291→          isPrimary: false,
   292→          labelOrder: selectedLabels.length + 1,
   293→          selectionRationale: `Secondary label: score (${candidate.score}) within gap (${scoreDifference} <= ${thresholds.secondaryLabelMinGap}) and above minimum confidence (${config.minSecondaryConfidence})`,
   294→        };
   295→        selectedLabels.push(secondaryLabel);
   296→      }
   297→    }
   298→  }
   299→}
   300→
   301→/**
   302→ * Check if category combination is allowed based on configuration
   303→ */
   304→function isCombinationAllowed(primaryCategory: string, candidateCategory: string, config: MultiLabelConfig): boolean {
   305→  if (primaryCategory === candidateCategory) {
   306→    return true;
   307→  }
   308→
   309→  // If strict mode is enabled and combinations are specified, only allow explicit combinations
   310→  if (config.strictCombinationMode && config.allowedCombinations.length > 0) {
   311→    return config.allowedCombinations.some((combo) => {
   312→      const categories = combo.categories;
   313→      return categories && categories.includes(primaryCategory) && categories.includes(candidateCategory);
   314→    });
   315→  }
   316→
   317→  // If no combinations specified, allow all (default permissive mode)
   318→  if (config.allowedCombinations.length === 0) {
   319→    return true;
   320→  }
   321→
   322→  // If combinations are specified but not in strict mode, still check them
   323→  const isExplicitlyAllowed = config.allowedCombinations.some((combo) => {
   324→    const categories = combo.categories;
   325→    return categories && categories.includes(primaryCategory) && categories.includes(candidateCategory);
   326→  });
   327→
   328→  // Allow explicitly configured combinations, and by default allow others too (unless strict mode)
   329→  return isExplicitlyAllowed || !config.strictCombinationMode;
   330→}
   331→
   332→/**
   333→ * Update category decisions based on selection results
   334→ */
   335→function updateCategoryDecisions(
   336→  candidateScores: Record<string, CategoryScore>,
   337→  selectedLabels: SelectedLabel[],
   338→  thresholds: ConfidenceThresholds
   339→): void {
   340→  const selectedCategoryNames = new Set(selectedLabels.map((label) => label.category));
   341→
   342→  for (const [categoryCode, scoreData] of Object.entries(candidateScores)) {
   343→    const score = scoreData.score || 0;
   344→
   345→    if (selectedCategoryNames.has(categoryCode)) {
   346→      // Selected categories get decision based on confidence
   347→      if (score >= thresholds.highConfidence) {
   348→        scoreData.decision = 'selected';
   349→        scoreData.decisionRationale = `High confidence (${score} >= ${thresholds.highConfidence}) - finalized without AI`;
   350→      } else if (score >= thresholds.mediumConfidence) {
   351→        scoreData.decision = 'candidate';
   352→        scoreData.decisionRationale = `Medium confidence (${score} >= ${thresholds.mediumConfidence}) - may need AI validation`;
   353→      } else {
   354→        scoreData.decision = 'candidate';
   355→        scoreData.decisionRationale = `Low confidence (${score} >= ${thresholds.lowConfidence}) - needs AI classification`;
   356→      }
   357→    } else {
   358→      // Non-selected categories are rejected
   359→      scoreData.decision = 'rejected';
   360→      if (score < thresholds.lowConfidence) {
   361→        scoreData.decisionRationale = `Below minimum threshold (${score} < ${thresholds.lowConfidence})`;
   362→      } else {
   363→        scoreData.decisionRationale = `Not selected despite adequate score (${score}) due to multi-label constraints`;
   364→      }
   365→    }
   366→  }
   367→}
   368→
   369→/**
   370→ * Determine if AI classification is needed based on selected labels
   371→ */
   372→function determineAiClassificationNeed(selectedLabels: SelectedLabel[], thresholds: ConfidenceThresholds): boolean {
   373→  if (selectedLabels.length === 0) {
   374→    return true; // No labels selected - need AI
   375→  }
   376→
   377→  // Check if primary label has high confidence (can skip AI)
   378→  const primaryLabel = selectedLabels.find((label) => label.isPrimary);
   379→  if (primaryLabel && primaryLabel.score >= thresholds.highConfidence) {
   380→    return false; // High confidence primary - skip AI
   381→  }
   382→
   383→  // Check if any label is below medium confidence (needs AI)
   384→  const hasLowConfidenceLabel = selectedLabels.some((label) => label.score < thresholds.mediumConfidence);
   385→  if (hasLowConfidenceLabel) {
   386→    return true; // Has low confidence labels - need AI
   387→  }
   388→
   389→  // Conservative approach for medium confidence range
   390→  return true;
   391→}
