    from: { email: 'sender@example.com', name: 'Sender', raw: 'Sender <sender@example.com>' },
    to: [{ email: 'recipient@example.com', name: 'Recipient', raw: 'Recipient <recipient@example.com>' }],
    date: new Date(),
    bodyPlain: 'Test email body content',
    isProcessed: false,
    processingPriority: 1,
  };

  // Minimal config for integration tests with financial and newsletter categories
  const minimalProcessingConfig: ProcessingConfig = {
    version: 1,
    taxonomyNotes: 'Integration test configuration',
    settings: {
      initialization: {
        applyHardAssertions: true,
        seedCategoryScores: true,
      },
      strongIndicators: {
        baseWeight: 60, // Higher weight for domain-based indicators
        diminishingReturnsFactor: 0.5,
      },
      ruleScoring: {
        useLexicalPatterns: true,
        applySubtypeRules: true,
        boundedAggregation: true,
      },
      attributeProcessing: {
        detectSelfSent: true,
        resolveDomains: true,
        deriveContextFlags: true,
      },
      attributeInfluence: {
        applyBonuses: true,
        applyPenalties: true,
        enforceCaps: true,
      },
      disambiguation: {
        pairwiseAdjustments: true,
        confidenceGapThreshold: 0.15,
      },
      multiLabelSelection: {
        maxLabels: 2,
        minSecondaryConfidence: 0.6,
        allowedCombinations: [],
        confidenceGapMinimum: 0.15,
      },
      aiRouting: {
        highConfidenceThreshold: 0.01, // Skip AI for any classification
        aiRequiredThreshold: 0.99, // Don't trigger AI
        skipAiConditions: [],
      },
    },
    confidenceThresholds: {
      highConfidence: 0.8,
      mediumConfidence: 0.5,
      lowConfidence: 0.3,
      aiClassificationRequired: 0.6,
      manualReviewRequired: 0.2,
      secondaryLabelMinGap: 0.15,
    },
    categorySignals: {
      financial: {
        hardAssertions: {},
        strongIndicators: {
          fromDomainsRef: {
            sourceGroup: 'financial',
            confidence: 'high',
          },
          subjectContains: ['account', 'statement', 'balance'],
        },
      },
      newsletter: {
        hardAssertions: {},
        strongIndicators: {
          fromDomainsRef: {
            sourceGroup: 'newsletter',
            confidence: 'high',
          },
          subjectContains: ['newsletter', 'digest', 'new stories'],
        },
      },
    },
    multiLabelPolicy: {
      maxTopLevelLabels: 2,
      minConfidenceForAdditional: 0.6,
      allowFinancialActionableCopresence: false,
      allowedCombinations: [],
      exclusions: [],
    },
    domainSignalOverrides: {},
    domainSignalResolution: {
      mode: 'runtimeResolved',
      source: 'config/domain-sources.json',
      notes: 'Test configuration',
    },
    topLevelCategories: {
      financial: {
        description: 'Financial and banking emails',
        subtypes: {},
        aiFinalClassification: {
          categoryDescription: 'Financial emails including banking, credit cards, and payments',
          decisionCriteria: ['Contains financial terminology', 'From known financial institutions'],
        },
      },
      newsletter: {
        description: 'Newsletter and digest emails',
        subtypes: {},
        aiFinalClassification: {
          categoryDescription: 'Newsletter and content digest emails',
          decisionCriteria: ['Contains newsletter patterns', 'From known newsletter platforms'],
        },
      },
    },
    attributes: {
      schema: {},
      detectors: [],
      derived: {},
      attributeBonusMap: {},
    },
    attributeRelevance: {
      RolesLegend: {
        CORE: 'Core attribute',
        PRIMARY_BOOST: 'Primary boost',
        SECONDARY_BOOST: 'Secondary boost',
        DISAMBIGUATOR: 'Disambiguator',
        FILTER: 'Filter',
        STRUCTURAL: 'Structural',
        DERIVED_LINK: 'Derived link',
        NEUTRAL: 'Neutral',
      },
    },
    aiPrompts: {
      featureExtraction: {
        systemPrompt: [],
        userPrompt: [],
        temperature: 0.7,
        maxTokens: 1000,
      },
      finalClassification: {
        systemPrompt: [],
        userPrompt: [],
        temperature: 0.7,
        maxTokens: 500,
      },
    },
    featureExtractionSchema: {
      type: 'object',
      properties: {},
      required: [],
      additionalProperties: false,
    },
  };

  const minimalConfig: CategoryConfiguration = {
    version: '1.0.0',
    lastModified: new Date(),
    hash: 'test-config-hash',
    processingConfig: minimalProcessingConfig,
    schemaVersion: '1.0',
    validationPassed: true,
    validationErrors: [],
    compiledRules: [],
    attributeMatrix: {},
  };

  describe('Domain Lookup Integration (T038a)', () => {
    it('should load domain lookup from config/domain-sources.json on initialization', () => {
      const pipeline = new ClassificationPipeline(minimalConfig);

      // Pipeline should initialize successfully with loaded domains
      expect(pipeline).toBeDefined();
    });

    it('should use loaded domains for hard assertions with financial category', async () => {
      const pipeline = new ClassificationPipeline(minimalConfig);

      // Create email from a known financial domain (chase.com from domain-sources.json)
      const financialEmail: EmailMessage = {
        ...mockEmail,
        id: 'financial-test-001',
        subject: 'Your Chase account statement',
        from: { email: 'alerts@chase.com', name: 'Chase', raw: 'Chase <alerts@chase.com>' },
        bodyPlain: 'Your account statement is ready.',
      };

      const result = await pipeline.classify(financialEmail);

      // Should classify with financial category due to domain lookup
      expect(result).toBeDefined();
      expect(result.primaryCategory).toBe('financial');
      expect(result.confidence).toBeGreaterThanOrEqual(0.7);

      // Verify domain lookup contributed to scoring
      expect(result.explainabilityTrace.strongIndicators).toContainEqual(
        expect.objectContaining({
          category: 'financial',
          indicatorType: 'fromDomain',
          matchedValue: 'chase.com',
        })
      );
    });

    it('should use loaded domains for strong indicators with newsletter category', async () => {
      const pipeline = new ClassificationPipeline(minimalConfig);

      // Create email from a known newsletter domain (medium.com from domain-sources.json)
      const newsletterEmail: EmailMessage = {
        ...mockEmail,
        id: 'newsletter-test-001',
        subject: 'New stories from Medium',
        from: { email: 'noreply@medium.com', name: 'Medium', raw: 'Medium <noreply@medium.com>' },
        bodyPlain: 'Check out these new stories...',
      };

      const result = await pipeline.classify(newsletterEmail);

      // Should classify with newsletter category due to domain lookup
      expect(result).toBeDefined();
      expect(result.primaryCategory).toBe('newsletter');
      expect(result.confidence).toBeGreaterThanOrEqual(0.5);

      // Verify domain lookup contributed to scoring
      expect(result.explainabilityTrace.strongIndicators).toContainEqual(
        expect.objectContaining({
          category: 'newsletter',
          indicatorType: 'fromDomain',
          matchedValue: 'medium.com',
        })
      );
    });

    it('should handle missing domain-sources.json gracefully', () => {
      // Pipeline initialization should not throw even if domain-sources.json is missing
      // (loadDomainLookup returns empty lookup with warning)
      expect(() => new ClassificationPipeline(minimalConfig)).not.toThrow();
    });
  });

  describe('Exclusion Rules Integration (T062)', () => {
    it('should correctly apply notContains rules to filter out unwanted emails', async () => {
      // Create config with notContains exclusion rules
      const configWithExclusions: CategoryConfiguration = {
        ...minimalConfig,
        processingConfig: {
          ...minimalConfig.processingConfig,
          topLevelCategories: {
            ...minimalConfig.processingConfig.topLevelCategories,
            subscriptionContent: {
              description: 'Subscription newsletters and digests',
              subtypes: {
                newsletter: {
                  description: 'Regular newsletters',
                  derived: false,
                  parallelSafe: true,
                  ruleBasedClassification: {
                    highConfidence: [
                      {
                        field: 'subject',
                        operation: 'containsAny',
                        values: ['newsletter', 'digest', 'weekly update'],
                        weight: 0.7,
                      },
                      {
                        field: 'subject',
                        operation: 'notContains',
                        values: ['unsubscribe', 'spam', 'advertisement'],
                        weight: 0.3,
                      },
                    ],
                  },
                },
              },
              aiFinalClassification: {
                categoryDescription: 'Subscription content and newsletters',
                decisionCriteria: ['Newsletter-like content without spam indicators'],
              },
            },
          },
          categorySignals: {
            ...minimalConfig.processingConfig.categorySignals,
            subscriptionContent: {
              hardAssertions: {},
              strongIndicators: {
                subjectContains: ['newsletter', 'digest'],
              },
            },
          },
        },
      };

      const pipeline = new ClassificationPipeline(configWithExclusions);

      // Test 1: Legitimate newsletter (no exclusion keywords) - should classify as subscriptionContent
      const legitimateNewsletter: EmailMessage = {
        ...mockEmail,
        id: 'newsletter-001',
        subject: 'Weekly Newsletter: Tech Updates',
        from: { email: 'info@techblog.com', name: 'Tech Blog', raw: 'Tech Blog <info@techblog.com>' },
        bodyPlain: "Here are this week's top stories...",
      };

      const result1 = await pipeline.classify(legitimateNewsletter);
      // Should classify as either newsletter or subscriptionContent (both match)
      expect(['newsletter', 'subscriptionContent']).toContain(result1.primaryCategory);
      const legitimateScore = result1.confidence;

      // Test 2: Newsletter with "unsubscribe" keyword - should have lower score or different category
      const spamNewsletter: EmailMessage = {
        ...mockEmail,
        id: 'newsletter-002',
        subject: 'Weekly Newsletter: Click here to unsubscribe',
        from: { email: 'spam@spammer.com', name: 'Spammer', raw: 'Spammer <spam@spammer.com>' },
        bodyPlain: 'Buy now! Limited time offer!',
      };

      const result2 = await pipeline.classify(spamNewsletter);
      // notContains rule should fail, reducing the score for subscriptionContent
      // Either different category, or if same categories then lower confidence
      if (result2.primaryCategory === 'subscriptionContent') {
        // subscriptionContent should have lower score due to failed notContains
        expect(result2.confidence).toBeLessThan(legitimateScore);
      }
      // Otherwise, it classified as something else which is also acceptable

      // Test 3: Newsletter with "advertisement" keyword - should be filtered out
      const advertisementEmail: EmailMessage = {
        ...mockEmail,
        id: 'newsletter-003',
        subject: 'Weekly Newsletter - Special Advertisement',
        from: { email: 'ads@advertiser.com', name: 'Advertiser', raw: 'Advertiser <ads@advertiser.com>' },
        bodyPlain: 'Check out our sponsors...',
      };

      const result3 = await pipeline.classify(advertisementEmail);
      // notContains rule should fail
      if (result3.primaryCategory === 'subscriptionContent') {
        expect(result3.confidence).toBeLessThan(legitimateScore);
      }
    });

    it('should apply notContains to body field for spam detection', async () => {
      const configWithBodyExclusions: CategoryConfiguration = {
        ...minimalConfig,
        processingConfig: {
          ...minimalConfig.processingConfig,
          topLevelCategories: {
            ...minimalConfig.processingConfig.topLevelCategories,
            professional: {
              description: 'Professional communications',
              subtypes: {
                correspondence: {
                  description: 'Professional email correspondence',
                  derived: false,
                  parallelSafe: true,
                  ruleBasedClassification: {
                    highConfidence: [
                      {
                        field: 'subject',
                        operation: 'containsAny',
                        values: ['meeting', 'project', 'review'],
                        weight: 0.5,
                      },
                      {
                        field: 'body',
                        operation: 'notContains',
                        values: ['click here', 'buy now', 'limited time offer'],
                        weight: 0.5,
                      },
                    ],
                  },
                },
              },
              aiFinalClassification: {
                categoryDescription: 'Professional work-related communications',
                decisionCriteria: ['Professional tone without spam indicators'],
              },
            },
          },
          categorySignals: {
            ...minimalConfig.processingConfig.categorySignals,
            professional: {
              hardAssertions: {},
              strongIndicators: {
                subjectContains: ['meeting', 'project'],
              },
            },
          },
        },
      };

      const pipeline = new ClassificationPipeline(configWithBodyExclusions);

      // Test 1: Professional email without spam keywords
      const professionalEmail: EmailMessage = {
        ...mockEmail,
        id: 'prof-001',
        subject: 'Project Review Meeting',
        from: { email: 'colleague@company.com', name: 'Colleague', raw: 'Colleague <colleague@company.com>' },
        bodyPlain: "Hi, let's schedule a meeting to review the project progress.",
        payload: {
          ...mockEmail.payload,
          body: {
            data: Buffer.from("Hi, let's schedule a meeting to review the project progress.").toString('base64url'),
          },
        },
      };

      const result1 = await pipeline.classify(professionalEmail);
      expect(result1.primaryCategory).toBe('professional');

      // Test 2: Email with spam keywords in body should be filtered
      const spamEmail: EmailMessage = {
        ...mockEmail,
        id: 'prof-002',
        subject: 'Project Update',
        from: { email: 'spammer@spam.com', name: 'Spammer', raw: 'Spammer <spammer@spam.com>' },
        bodyPlain: 'Click here to buy now! Limited time offer on our project management tools.',
        payload: {
          ...mockEmail.payload,
          body: {
            data: Buffer.from('Click here to buy now! Limited time offer on our project management tools.').toString(
              'base64url'
            ),
          },
        },
      };

      const result2 = await pipeline.classify(spamEmail);
      // notContains rule should fail due to spam keywords in body
      if (result2.primaryCategory === 'professional') {
        expect(result2.confidence).toBeLessThan(result1.confidence);
      } else {
        expect(result2.primaryCategory).not.toBe('professional');
      }
    });
  });
});

